mapper.select:
select hr.*,
       cp.child_name,
       t.real_name as teacher_name
from health_record hr
         left join child_profile cp on hr.child_id = cp.id
         left join sys_user t on hr.teacher_id = t.id


        and hr.child_id = #{childId}


        and hr.teacher_id = #{teacherId}


        and cp.parent_id = #{parentId}


order by hr.id desc

mapper.update:
update health_record
child_id = #{childId}, teacher_id = #{teacherId}, record_date = #{recordDate}, temperature = #{temperature}, health_status = #{healthStatus}, emotion_status = #{emotionStatus}, attendance_advice = #{attendanceAdvice}, remark = #{remark},
where id = #{id}
